+bool ExportJwkSlhDsaKey(Environment* env,
+                        const KeyObjectData& key,
+                        Local<Object> target) {
+  Mutex::ScopedLock lock(key.mutex());
+  const auto& pkey = key.GetAsymmetricKey();
+
+  const char* alg = GetSlhDsaAlgorithmName(pkey.id());
+  CHECK(alg);
