+const fs = require('fs');
+const path = require('path');
+
+const createTempFixture = (suiteRoot, name, sourcePath, tsconfig, packageJson) => {
+  const tempRoot = fs.mkdtempSync(path.join(suiteRoot, `.tmp-module-${name}-`));
